import{_ as t}from"./chunks/mario.B07hY3N3.js";import{c as o,Q as r,j as a,m as i}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Mario AIO","description":"Connection, setup and firmware update guide for the OpenIPC Mario AIO module for FPV.","frontmatter":{"title":"Mario AIO","description":"Connection, setup and firmware update guide for the OpenIPC Mario AIO module for FPV.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/hardware/vtx/marioaio"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/hardware/vtx/marioaio"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/hardware/vtx/marioaio"}],["meta",{"property":"og:title","content":"Mario AIO"}],["meta",{"property":"og:description","content":"Connection, setup and firmware update guide for the OpenIPC Mario AIO module for FPV."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"name":"twitter:title","content":"Mario AIO"}],["meta",{"name":"twitter:description","content":"Connection, setup and firmware update guide for the OpenIPC Mario AIO module for FPV."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Hardware\\",\\"item\\":\\"https://openfpv.com.ua/en/hardware/vtx/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Mario AIO\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Mario AIO\\",\\"description\\":\\"Connection, setup and firmware update guide for the OpenIPC Mario AIO module for FPV.\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/hardware/vtx/marioaio\\",\\"image\\":\\"https://openfpv.com.ua/og-hardware.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/hardware/vtx/marioaio.md","filePath":"en/hardware/vtx/marioaio.md","lastUpdated":1780228136000}'),n={name:"en/hardware/vtx/marioaio.md"};function d(l,e,s,p,c,h){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="openipc-mario-aio" tabindex="-1">OpenIPC Mario AIO <a class="header-anchor" href="#openipc-mario-aio" aria-label="Permalink to &quot;OpenIPC Mario AIO&quot;">​</a></h1><img src="'+t+'" alt="" width="400px"><p><strong>OpenIPC Mario AIO</strong> is a compact module for a digital FPV system that combines a camera, a transmitter (VTX) and a system-on-chip (SoC). It is designed for use in drones and other FPV projects, providing high image quality and low video latency.</p><hr><h3 id="key-specifications" tabindex="-1">Key specifications <a class="header-anchor" href="#key-specifications" aria-label="Permalink to &quot;Key specifications&quot;">​</a></h3><table style="width:100%;border-collapse:collapse;margin:15px 0;"><thead><tr><th style="padding:10px;border:1px solid #ddd;text-align:left;">Specification</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Value</th></tr></thead><tbody><tr><td style="padding:8px;border:1px solid #ddd;">Board size</td><td style="padding:8px;border:1px solid #ddd;">30×32 mm</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Mounting holes</td><td style="padding:8px;border:1px solid #ddd;">4× M2</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Heatsink holes</td><td style="padding:8px;border:1px solid #ddd;">20×20 mm</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Power</td><td style="padding:8px;border:1px solid #ddd;">2S–6S LiPo</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">BEC output (RF)</td><td style="padding:8px;border:1px solid #ddd;">5V up to 3A</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">BEC output (MSIC)</td><td style="padding:8px;border:1px solid #ddd;">5V up to 2A</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Interfaces</td><td style="padding:8px;border:1px solid #ddd;">UART, USB, Ethernet</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">SD card support</td><td style="padding:8px;border:1px solid #ddd;">Yes</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">Cooling</td><td style="padding:8px;border:1px solid #ddd;">Built-in heatsink and fan</td></tr></tbody></table><img src="https://github.com/user-attachments/assets/ad675599-61ce-4cec-a9bf-5933d907c53a" alt="" width="600px"><hr><h3 id="power-and-connection" tabindex="-1">Power and connection <a class="header-anchor" href="#power-and-connection" aria-label="Permalink to &quot;Power and connection&quot;">​</a></h3><ul><li>Powered by a 2S–6S battery</li><li>For low voltage (2S–3S) it is recommended to connect <strong>4 power wires</strong> through a separate connector — more current is required.</li><li>For 4S and above you can use the standard <strong>2-wire</strong> connection.</li><li>To lower the minimum supply voltage to ~5.4 V you <strong>can remove two resistors</strong> on the board.</li></ul><hr><h3 id="uart-pads-and-entering-u-boot" tabindex="-1">UART pads and entering U-Boot <a class="header-anchor" href="#uart-pads-and-entering-u-boot" aria-label="Permalink to &quot;UART pads and entering U-Boot&quot;">​</a></h3><p>To enter U-Boot boot mode (debug mode) use the UART:<br><strong>R0 / T0</strong> — pads on the top of the board.</p><hr><h3 id="led-indicators" tabindex="-1">LED indicators <a class="header-anchor" href="#led-indicators" aria-label="Permalink to &quot;LED indicators&quot;">​</a></h3><ul><li><strong>Red blinking</strong> — battery power is on</li><li><strong>Red solid</strong> — Ethernet/USB connection</li><li><strong>Blue blinking</strong> — RF transmitter active</li><li><strong>Green</strong> — TBD (not implemented or changing)</li></ul><hr><img src="https://github.com/user-attachments/assets/e10e6671-553f-4840-aacd-16816be0813b" alt="" width="600px"><hr><h3 id="connecting-to-the-flight-controller" tabindex="-1">Connecting to the flight controller <a class="header-anchor" href="#connecting-to-the-flight-controller" aria-label="Permalink to &quot;Connecting to the flight controller&quot;">​</a></h3><p>To connect the Mario AIO to a flight controller (e.g. SpeedyBee F405 WING) use the following connections:</p><ul><li><strong>GND</strong> → GND on the controller</li><li><strong>VCC</strong> → VCC (check voltage compatibility)</li><li><strong>RX</strong> → TX on the controller</li><li><strong>TX</strong> → RX on the controller</li></ul><blockquote><p>⚠️ Before powering on, make sure all connections are correct.</p></blockquote><hr><h3 id="setup-and-firmware-update" tabindex="-1">Setup and firmware update <a class="header-anchor" href="#setup-and-firmware-update" aria-label="Permalink to &quot;Setup and firmware update&quot;">​</a></h3><h3 id="connecting-via-usb" tabindex="-1">Connecting via USB <a class="header-anchor" href="#connecting-via-usb" aria-label="Permalink to &quot;Connecting via USB&quot;">​</a></h3><ol><li>Connect the Mario AIO to your computer with a USB cable.</li><li>If the device is not recognized, install the <a href="https://github.com/user-attachments/files/16829005/corechip-sr9900-usb20-to-fast-ethernet-adapter-1750095.zip" target="_blank" rel="noreferrer"><strong>corechip-sr9900</strong></a> driver.</li><li>Configure the USB network adapter: <ul><li>IP address: <code>192.168.1.11</code></li><li>Subnet mask: <code>255.255.255.0</code></li></ul></li><li>Connect to the Mario AIO via SSH: <ul><li>IP address: <code>192.168.1.10</code></li><li>Login: <code>root</code></li><li>Password: <code>12345</code></li></ul></li></ol><h3 id="updating-the-firmware" tabindex="-1">Updating the firmware <a class="header-anchor" href="#updating-the-firmware" aria-label="Permalink to &quot;Updating the firmware&quot;">​</a></h3><ol><li>Download the <a href="https://github.com/OpenIPC/openipc-configurator/releases/" target="_blank" rel="noreferrer">Multiplatform Configurator</a>.</li><li>Firmware - OpenIPC - MarioAIO - click Update.</li></ol><blockquote><p>⚠️ Before updating the firmware it is recommended to back up your settings.</p></blockquote><hr><h3 id="rf-settings" tabindex="-1">RF settings <a class="header-anchor" href="#rf-settings" aria-label="Permalink to &quot;RF settings&quot;">​</a></h3><ul><li><strong>Maximum RF power</strong>: 18 dBm</li><li><strong>Recommended settings</strong>: <ul><li><code>stbc=1</code>, <code>ldpc=1</code></li><li><code>mcs</code> index: 1 or 3</li><li>Video bitrate: 4096 / 8192 / 12688</li></ul></li></ul><blockquote><p>⚠️ It is recommended to limit Txpower to 1 when powering via USB only.</p></blockquote><hr><h3 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h3><ul><li><a href="https://github.com/OpenIPC/wiki" target="_blank" rel="noreferrer">OpenIPC Wiki</a></li><li><a href="https://github.com/OpenIPC/configurator" target="_blank" rel="noreferrer">OpenIPC Configurator</a></li><li><a href="https://www.youtube.com/watch?v=bgfCEThN3Kg" target="_blank" rel="noreferrer">Mario AIO video review</a></li></ul>',37)])])}const f=o(n,[["render",d]]);export{m as __pageData,f as default};
